content:
## 来源

{{ source }}

## 世界

- id: {{ world.id }}
- 名称: {{ world.name }}
- 描述: {{ world.description }}

## 模拟

- id: {{ simulation.id }}
- 当前时间: {{ simulation.current_time }}

## 当前回合

- id: {{ turn.id }}
- sequence: {{ turn.sequence }}
- type: {{ turn.type }}
- content: {{ turn.content }}
- start time: {{ turn.start_time }}

## 用户输入

{{ user_input }}

## 叙述

{{ narration }}

## 已接受行动

{% for entry in coordination_result.accepted_actions %}
accepted:{{ loop.index0 }}:
- actor id: {{ entry.actor_id }}
- action index: {{ entry.action_index }}
- summary: {{ entry.summary }}
- action type: {{ entry.action.type }}
- label: {{ entry.action.label }}
- target ids: {{ entry.action.target_ids }}
- utterance: {{ entry.action.utterance }}
- expected effects: {{ entry.action.expected_effects }}
{% else %}
- 无
{% endfor %}

## 已提交的物理变化

{% for operation in state_commit.operations %}
Operation {{ loop.index0 }}:
{{ operation }}
{% else %}
- 无
{% endfor %}

## 行动者、近期记忆与活跃意图

{% for entry in actors %}
Actor {{ entry.actor.id }}: {{ entry.actor.name }}
- 公开状态: {{ entry.actor.public_state }}
- 私密状态: {{ entry.actor.private_state }}
- 当前活动: {{ entry.actor.current_activity.name }}

近期记忆:
{% for memory in entry.recent_memories %}
- memory id: {{ memory.memory.id }}; 摘要: {{ memory.memory.summary }}; event id: {{ memory.event.id }}; event name: {{ memory.event.name }}; support: {{ memory.support_type }}; confidence: {{ memory.confidence }}; salience: {{ memory.salience }}; stance: {{ memory.stance }}{% if memory.behavioural_relevance %}; 行为相关性: {{ memory.behavioural_relevance }}{% endif %}
{% else %}
- 无
{% endfor %}

活跃意图:
{% for intent in entry.intents %}
- intent id: {{ intent.id }}; 名称: {{ intent.name }}; type: {{ intent.type }}; status: {{ intent.status }}; priority: {{ intent.priority }}; urgency: {{ intent.urgency }}; horizon: {{ intent.horizon }}{% if intent.deadline %}; deadline: {{ intent.deadline }}{% endif %}
  描述: {{ intent.description }}
  期望状态: {{ intent.desired_state }}
  成功条件: {{ intent.success_conditions }}
  失败条件: {{ intent.failure_conditions }}
  当前计划: {{ intent.current_plan }}
  阻碍: {{ intent.blockers }}
  未结线索: {{ intent.open_threads }}
{% else %}
- 无
{% endfor %}
{% else %}
- 无
{% endfor %}
